import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    setSaved(true);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md">
        <input type="text" value={title} onChange={e => setTitle(e.target.value)} className="bg-transparent border-b-2 border-[#C06C88] p-2 w-full text-lg" placeholder="Title" maxLength="50"/>
        <textarea value={content} onChange={e => setContent(e.target.value)} className="bg-transparent border-b-2 border-[#C06C88] p-2 w-full h-24 text-lg" placeholder="Content"/>
        <button className="bg-[#411C56] text-white p-2 rounded-md hover:bg-[#C06C88]" onClick={handleSave}>Save</button>
        {saved && <p className="text-green-500">Post saved successfully!</p>}
      </div>
    </div>
  );
};

export default App;
